/**
 * Notification log model — records of sent notifications for history tracking.
 *
 * Each log entry captures: recipient, channel, type, timestamp, and delivery status.
 */

import type { NotificationChannel, NotificationType, NotificationPriority } from './notification.js';

export type DeliveryStatus = 'delivered' | 'failed' | 'suppressed';

export interface NotificationLog {
  id: string;
  notificationId: string;
  recipient: string;
  channel: NotificationChannel;
  type: NotificationType;
  subject: string;
  priority: NotificationPriority;
  status: DeliveryStatus;
  error?: string;
  metadata?: Record<string, unknown>;
  createdAt: Date;
  deliveredAt?: Date;
}

export interface NotificationHistoryQuery {
  recipient?: string;
  type?: NotificationType;
  channel?: NotificationChannel;
  status?: DeliveryStatus;
  fromDate?: Date;
  toDate?: Date;
}

/**
 * Repository for notification log data access.
 *
 * Extends BaseRepository with query methods for filtering notification history
 * by recipient, type, channel, status, and date range.
 */

import type { DatabaseRecord } from '../utils/database.js';
import type { Database } from '../utils/database.js';
import type { NotificationLog, NotificationHistoryQuery } from '../models/notification-log.js';
import type { NotificationChannel, NotificationType, NotificationPriority } from '../models/notification.js';
import type { DeliveryStatus } from '../models/notification-log.js';
import { BaseRepository } from './base.repository.js';

export class NotificationLogRepository extends BaseRepository<NotificationLog> {
  constructor(db: Database) {
    super(db, 'notification_logs');
  }

  protected toDomain(record: DatabaseRecord): NotificationLog {
    return {
      id: record['id'] as string,
      notificationId: record['notificationId'] as string,
      recipient: record['recipient'] as string,
      channel: record['channel'] as NotificationChannel,
      type: record['type'] as NotificationType,
      subject: record['subject'] as string,
      priority: record['priority'] as NotificationPriority,
      status: record['status'] as DeliveryStatus,
      error: record['error'] as string | undefined,
      metadata: record['metadata'] ? JSON.parse(record['metadata'] as string) as Record<string, unknown> : undefined,
      createdAt: new Date(record['createdAt'] as string),
      deliveredAt: record['deliveredAt'] ? new Date(record['deliveredAt'] as string) : undefined,
    };
  }

  protected toRecord(entity: NotificationLog): DatabaseRecord {
    return {
      id: entity.id,
      notificationId: entity.notificationId,
      recipient: entity.recipient,
      channel: entity.channel,
      type: entity.type,
      subject: entity.subject,
      priority: entity.priority,
      status: entity.status,
      error: entity.error,
      metadata: entity.metadata ? JSON.stringify(entity.metadata) : undefined,
      createdAt: entity.createdAt.toISOString(),
      deliveredAt: entity.deliveredAt?.toISOString(),
    };
  }

  /**
   * Query notification logs with filters.
   */
  query(filters: NotificationHistoryQuery): NotificationLog[] {
    return this.findAll((log) => {
      if (filters.recipient && log.recipient !== filters.recipient) return false;
      if (filters.type && log.type !== filters.type) return false;
      if (filters.channel && log.channel !== filters.channel) return false;
      if (filters.status && log.status !== filters.status) return false;
      if (filters.fromDate && log.createdAt < filters.fromDate) return false;
      if (filters.toDate && log.createdAt > filters.toDate) return false;
      return true;
    });
  }

  /**
   * Find all logs for a specific recipient.
   */
  findByRecipient(recipient: string): NotificationLog[] {
    return this.findAll((log) => log.recipient === recipient);
  }

  /**
   * Find all logs of a specific notification type.
   */
  findByType(type: NotificationType): NotificationLog[] {
    return this.findAll((log) => log.type === type);
  }
}

/**
 * Notification history service — logs and queries sent notifications.
 *
 * Integrates with NotificationService to record every delivery attempt.
 * Provides query methods for filtering history by user, type, date range, etc.
 */

import type { NotificationLog, NotificationHistoryQuery, DeliveryStatus } from '../models/notification-log.js';
import type { NotificationLogRepository } from '../repositories/notification-log.repository.js';
import type { NotificationResult, NotificationPayload } from '../models/notification.js';
import type { PaginationResult } from '../utils/pagination.js';
import { paginate } from '../utils/pagination.js';
import { Logger } from '../utils/logger.js';

let nextLogId = 1;

function generateLogId(): string {
  return `nlog-${String(nextLogId++).padStart(4, '0')}`;
}

export function resetNotificationLogIdCounter(): void {
  nextLogId = 1;
}

export class NotificationHistoryService {
  private logger = new Logger('NotificationHistoryService');

  constructor(private repository: NotificationLogRepository) {}

  /**
   * Record a notification delivery attempt.
   * Called by NotificationService after each send attempt.
   */
  record(payload: NotificationPayload, result: NotificationResult): NotificationLog {
    let status: DeliveryStatus;
    if (result.success) {
      status = 'delivered';
    } else if (result.error === 'Suppressed by user preferences') {
      status = 'suppressed';
    } else {
      status = 'failed';
    }

    const log: NotificationLog = {
      id: generateLogId(),
      notificationId: payload.id,
      recipient: payload.recipient,
      channel: payload.channel,
      type: payload.type,
      subject: payload.subject,
      priority: payload.priority,
      status,
      error: result.error,
      metadata: payload.metadata,
      createdAt: payload.createdAt,
      deliveredAt: result.deliveredAt,
    };

    this.repository.save(log);
    this.logger.info(`Recorded notification ${payload.id} — status: ${status}`);
    return log;
  }

  /**
   * Query notification history with filters.
   */
  query(filters: NotificationHistoryQuery): NotificationLog[] {
    return this.repository.query(filters);
  }

  /**
   * Query notification history with pagination.
   */
  queryPaginated(
    filters: NotificationHistoryQuery,
    page: number = 1,
    pageSize: number = 20,
  ): PaginationResult<NotificationLog> {
    const results = this.repository.query(filters);
    return paginate(results, page, pageSize);
  }

  /**
   * Get all notification logs for a recipient.
   */
  getByRecipient(recipient: string): NotificationLog[] {
    return this.repository.findByRecipient(recipient);
  }

  /**
   * Get all notification logs of a specific type.
   */
  getByType(type: NotificationHistoryQuery['type']): NotificationLog[] {
    if (!type) return [];
    return this.repository.findByType(type);
  }

  /**
   * Get all notification logs within a date range.
   */
  getByDateRange(fromDate: Date, toDate: Date): NotificationLog[] {
    return this.repository.query({ fromDate, toDate });
  }

  /**
   * Get a single log entry by ID.
   */
  getById(id: string): NotificationLog | undefined {
    return this.repository.findById(id);
  }

  /**
   * Get total count of logged notifications.
   */
  count(): number {
    return this.repository.count();
  }
}

