import { describe, it, expect, beforeEach } from 'vitest';
import { Database } from '../../src/utils/database.js';
import { EventBus } from '../../src/events/event-bus.js';
import { NotificationLogRepository } from '../../src/repositories/notification-log.repository.js';
import {
  NotificationHistoryService,
  resetNotificationLogIdCounter,
} from '../../src/services/notification-history.service.js';
import {
  NotificationService,
  resetNotificationIdCounter,
} from '../../src/services/notification.service.js';
import { EmailNotificationAdapter } from '../../src/adapters/email.adapter.js';
import type { NotificationPayload, NotificationResult } from '../../src/models/notification.js';
import type { OrderCreatedEvent, OrderStatusChangedEvent, UserCreatedEvent } from '../../src/events/event-types.js';

describe('NotificationHistoryService', () => {
  let db: Database;
  let repository: NotificationLogRepository;
  let historyService: NotificationHistoryService;

  beforeEach(() => {
    db = new Database();
    repository = new NotificationLogRepository(db);
    historyService = new NotificationHistoryService(repository);
    resetNotificationLogIdCounter();
  });

  describe('record', () => {
    it('should record a successful delivery', () => {
      const payload: NotificationPayload = {
        id: 'notif-0001',
        type: 'order-confirmation',
        channel: 'email',
        recipient: 'alice@example.com',
        subject: 'Order Confirmation',
        body: 'Your order has been placed.',
        priority: 'normal',
        createdAt: new Date('2026-01-01T10:00:00Z'),
        metadata: { userId: 'user-1' },
      };
      const result: NotificationResult = {
        notificationId: 'notif-0001',
        channel: 'email',
        success: true,
        deliveredAt: new Date('2026-01-01T10:00:01Z'),
      };

      const log = historyService.record(payload, result);

      expect(log.id).toBe('nlog-0001');
      expect(log.notificationId).toBe('notif-0001');
      expect(log.recipient).toBe('alice@example.com');
      expect(log.channel).toBe('email');
      expect(log.type).toBe('order-confirmation');
      expect(log.subject).toBe('Order Confirmation');
      expect(log.priority).toBe('normal');
      expect(log.status).toBe('delivered');
      expect(log.error).toBeUndefined();
      expect(log.metadata).toEqual({ userId: 'user-1' });
    });

    it('should record a failed delivery', () => {
      const payload: NotificationPayload = {
        id: 'notif-0002',
        type: 'welcome',
        channel: 'email',
        recipient: 'bob@example.com',
        subject: 'Welcome',
        body: 'Welcome!',
        priority: 'low',
        createdAt: new Date('2026-01-01T10:00:00Z'),
      };
      const result: NotificationResult = {
        notificationId: 'notif-0002',
        channel: 'email',
        success: false,
        error: 'No adapter for channel: email',
        deliveredAt: new Date('2026-01-01T10:00:01Z'),
      };

      const log = historyService.record(payload, result);

      expect(log.status).toBe('failed');
      expect(log.error).toBe('No adapter for channel: email');
    });

    it('should record a suppressed notification', () => {
      const payload: NotificationPayload = {
        id: 'notif-0003',
        type: 'order-status-update',
        channel: 'email',
        recipient: 'carol@example.com',
        subject: 'Order Update',
        body: 'Status changed.',
        priority: 'normal',
        createdAt: new Date('2026-01-01T10:00:00Z'),
      };
      const result: NotificationResult = {
        notificationId: 'notif-0003',
        channel: 'email',
        success: false,
        error: 'Suppressed by user preferences',
        deliveredAt: new Date('2026-01-01T10:00:01Z'),
      };

      const log = historyService.record(payload, result);

      expect(log.status).toBe('suppressed');
      expect(log.error).toBe('Suppressed by user preferences');
    });

    it('should generate sequential log IDs', () => {
      const payload: NotificationPayload = {
        id: 'notif-0001',
        type: 'welcome',
        channel: 'email',
        recipient: 'a@b.com',
        subject: 'Hi',
        body: 'Hello',
        priority: 'low',
        createdAt: new Date(),
      };
      const result: NotificationResult = {
        notificationId: 'notif-0001',
        channel: 'email',
        success: true,
        deliveredAt: new Date(),
      };

      const log1 = historyService.record(payload, result);
      const log2 = historyService.record({ ...payload, id: 'notif-0002' }, { ...result, notificationId: 'notif-0002' });

      expect(log1.id).toBe('nlog-0001');
      expect(log2.id).toBe('nlog-0002');
    });
  });

  describe('query', () => {
    beforeEach(() => {
      const deliveries: Array<{ payload: NotificationPayload; result: NotificationResult }> = [
        {
          payload: {
            id: 'notif-0001', type: 'order-confirmation', channel: 'email',
            recipient: 'alice@example.com', subject: 'Order 1', body: 'body',
            priority: 'normal', createdAt: new Date('2026-01-01T10:00:00Z'),
            metadata: { userId: 'user-1' },
          },
          result: { notificationId: 'notif-0001', channel: 'email', success: true, deliveredAt: new Date('2026-01-01T10:00:01Z') },
        },
        {
          payload: {
            id: 'notif-0002', type: 'welcome', channel: 'email',
            recipient: 'bob@example.com', subject: 'Welcome Bob', body: 'body',
            priority: 'low', createdAt: new Date('2026-01-02T10:00:00Z'),
          },
          result: { notificationId: 'notif-0002', channel: 'email', success: true, deliveredAt: new Date('2026-01-02T10:00:01Z') },
        },
        {
          payload: {
            id: 'notif-0003', type: 'order-status-update', channel: 'webhook',
            recipient: 'alice@example.com', subject: 'Order Update', body: 'body',
            priority: 'high', createdAt: new Date('2026-01-03T10:00:00Z'),
          },
          result: { notificationId: 'notif-0003', channel: 'webhook', success: false, error: 'Timeout', deliveredAt: new Date('2026-01-03T10:00:05Z') },
        },
      ];

      for (const d of deliveries) {
        historyService.record(d.payload, d.result);
      }
    });

    it('should query by recipient', () => {
      const results = historyService.query({ recipient: 'alice@example.com' });
      expect(results).toHaveLength(2);
      expect(results.every((r) => r.recipient === 'alice@example.com')).toBe(true);
    });

    it('should query by type', () => {
      const results = historyService.query({ type: 'welcome' });
      expect(results).toHaveLength(1);
      expect(results[0]?.type).toBe('welcome');
    });

    it('should query by channel', () => {
      const results = historyService.query({ channel: 'webhook' });
      expect(results).toHaveLength(1);
      expect(results[0]?.channel).toBe('webhook');
    });

    it('should query by status', () => {
      const results = historyService.query({ status: 'failed' });
      expect(results).toHaveLength(1);
      expect(results[0]?.notificationId).toBe('notif-0003');
    });

    it('should query by date range', () => {
      const results = historyService.query({
        fromDate: new Date('2026-01-02T00:00:00Z'),
        toDate: new Date('2026-01-02T23:59:59Z'),
      });
      expect(results).toHaveLength(1);
      expect(results[0]?.recipient).toBe('bob@example.com');
    });

    it('should combine multiple filters', () => {
      const results = historyService.query({
        recipient: 'alice@example.com',
        channel: 'email',
      });
      expect(results).toHaveLength(1);
      expect(results[0]?.type).toBe('order-confirmation');
    });

    it('should return empty array when no matches', () => {
      const results = historyService.query({ recipient: 'nobody@example.com' });
      expect(results).toHaveLength(0);
    });
  });

  describe('queryPaginated', () => {
    beforeEach(() => {
      for (let i = 1; i <= 5; i++) {
        historyService.record(
          {
            id: `notif-${i}`, type: 'welcome', channel: 'email',
            recipient: 'alice@example.com', subject: `Notif ${i}`, body: 'body',
            priority: 'low', createdAt: new Date(`2026-01-0${i}T10:00:00Z`),
          },
          { notificationId: `notif-${i}`, channel: 'email', success: true, deliveredAt: new Date() },
        );
      }
    });

    it('should paginate results', () => {
      const page1 = historyService.queryPaginated({ recipient: 'alice@example.com' }, 1, 2);
      expect(page1.items).toHaveLength(2);
      expect(page1.totalItems).toBe(5);
      expect(page1.totalPages).toBe(3);
      expect(page1.hasNext).toBe(true);
      expect(page1.hasPrevious).toBe(false);
    });

    it('should return last page correctly', () => {
      const page3 = historyService.queryPaginated({ recipient: 'alice@example.com' }, 3, 2);
      expect(page3.items).toHaveLength(1);
      expect(page3.hasNext).toBe(false);
      expect(page3.hasPrevious).toBe(true);
    });
  });

  describe('convenience methods', () => {
    beforeEach(() => {
      historyService.record(
        {
          id: 'notif-0001', type: 'order-confirmation', channel: 'email',
          recipient: 'alice@example.com', subject: 'Order', body: 'body',
          priority: 'normal', createdAt: new Date('2026-01-01T10:00:00Z'),
        },
        { notificationId: 'notif-0001', channel: 'email', success: true, deliveredAt: new Date() },
      );
      historyService.record(
        {
          id: 'notif-0002', type: 'welcome', channel: 'email',
          recipient: 'bob@example.com', subject: 'Welcome', body: 'body',
          priority: 'low', createdAt: new Date('2026-01-02T10:00:00Z'),
        },
        { notificationId: 'notif-0002', channel: 'email', success: true, deliveredAt: new Date() },
      );
    });

    it('should get logs by recipient', () => {
      expect(historyService.getByRecipient('alice@example.com')).toHaveLength(1);
      expect(historyService.getByRecipient('bob@example.com')).toHaveLength(1);
      expect(historyService.getByRecipient('nobody@example.com')).toHaveLength(0);
    });

    it('should get logs by type', () => {
      expect(historyService.getByType('order-confirmation')).toHaveLength(1);
      expect(historyService.getByType('welcome')).toHaveLength(1);
      expect(historyService.getByType('account-updated')).toHaveLength(0);
    });

    it('should get logs by date range', () => {
      const results = historyService.getByDateRange(
        new Date('2026-01-01T00:00:00Z'),
        new Date('2026-01-01T23:59:59Z'),
      );
      expect(results).toHaveLength(1);
      expect(results[0]?.recipient).toBe('alice@example.com');
    });

    it('should get log by ID', () => {
      const log = historyService.getById('nlog-0001');
      expect(log).toBeDefined();
      expect(log?.notificationId).toBe('notif-0001');
    });

    it('should return undefined for non-existent ID', () => {
      expect(historyService.getById('nlog-9999')).toBeUndefined();
    });

    it('should count logged notifications', () => {
      expect(historyService.count()).toBe(2);
    });

    it('should return empty array for undefined type', () => {
      expect(historyService.getByType(undefined)).toHaveLength(0);
    });
  });

  describe('integration with NotificationService', () => {
    let eventBus: EventBus;
    let notificationService: NotificationService;

    beforeEach(() => {
      eventBus = new EventBus();
      notificationService = new NotificationService(eventBus, { historyService });
      const emailAdapter = new EmailNotificationAdapter({});
      notificationService.registerAdapter(emailAdapter);
      resetNotificationIdCounter();
    });

    it('should log notifications sent via event handlers', async () => {
      const event: OrderCreatedEvent = {
        type: 'order:created',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [{ productId: 'p1', name: 'Widget', quantity: 2, unitPrice: 10 }],
          total: 20,
          status: 'pending',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        user: {
          id: 'user-1',
          name: 'Alice',
          email: 'alice@example.com',
          role: 'member',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        timestamp: new Date(),
      };

      await eventBus.emit(event);

      expect(historyService.count()).toBe(1);
      const logs = historyService.getByRecipient('alice@example.com');
      expect(logs).toHaveLength(1);
      expect(logs[0]?.type).toBe('order-confirmation');
      expect(logs[0]?.status).toBe('delivered');
      expect(logs[0]?.channel).toBe('email');
    });

    it('should log multiple notifications from different events', async () => {
      await eventBus.emit({
        type: 'user:created',
        user: {
          id: 'user-1', name: 'Alice', email: 'alice@example.com',
          role: 'member', createdAt: new Date(), updatedAt: new Date(),
        },
        timestamp: new Date(),
      } as UserCreatedEvent);

      await eventBus.emit({
        type: 'order:status-changed',
        order: {
          id: 'order-1', userId: 'user-1', items: [], total: 20,
          status: 'confirmed', createdAt: new Date(), updatedAt: new Date(),
        },
        previousStatus: 'pending',
        newStatus: 'confirmed',
        timestamp: new Date(),
      } as OrderStatusChangedEvent);

      expect(historyService.count()).toBe(2);
      const welcomeLogs = historyService.getByType('welcome');
      expect(welcomeLogs).toHaveLength(1);
      const statusLogs = historyService.getByType('order-status-update');
      expect(statusLogs).toHaveLength(1);
    });

    it('should log failed notifications when no adapter registered', async () => {
      const noAdapterService = new NotificationService(eventBus, { historyService });
      // Don't register any adapter — use a fresh eventBus to avoid double-handler
      const freshBus = new EventBus();
      const freshService = new NotificationService(freshBus, { historyService });

      await freshService.send({
        type: 'welcome',
        channel: 'sms',
        recipient: 'alice@example.com',
        subject: 'Test',
        body: 'Test body',
        priority: 'normal',
      });

      const logs = historyService.query({ status: 'failed' });
      expect(logs).toHaveLength(1);
      expect(logs[0]?.error).toContain('No adapter for channel');
    });
  });
